const projects = new Map();

export function addProject(name) {
  if (!name) throw new Error('Name is required');
  const id = randomUUID();
  projects.set(id, { id, name });
  return { id, name };
}

export function getProject(projectId) {
  const project = projects.get(projectId);
  if (!project) throw new Error('Project not found');
  return project;
}

const tasks = new Map();

export function addTask(projectId, data) {
  const id = randomUUID();
  tasks.set(id, { projectId, ...data });
  return { id, ...data };
}

export function getTasks(projectId, status) {
  if (status && !['todo', 'done'].includes(status)) throw new Error('Invalid task status');
  const filteredTasks = Array.from(tasks.values()).filter(task => task.projectId === projectId);
  return status ? filteredTasks.filter(task => task.status === status) : filteredTasks;
}

export function updateTaskStatus(taskId, newStatus) {
  const task = tasks.get(taskId);
  if (!task) throw new Error('Task not found');
  task.status = newStatus;
  return { ...task };
}

import express from 'express';
const router = express.Router();
import { addProject, getProject } from './service.js';
import { sendError } from '../../lib/errors.js';

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) return sendError(res, 400, 'BadRequestError', 'Name is required');
  try {
    addProject(name);
    res.status(201).send({ project: { id: projects.size, name } });
  } catch (error) {
    sendError(res, 500, 'InternalServerError', error.message);
  }
});

router.get('/:id', (req, res) => {
  const project = getProject(req.params.id);
  if (!project) return sendError(res, 404, 'NotFoundError', 'Project not found');
  try {
    res.send({ project });
  } catch (error) {
    sendError(res, 500, 'InternalServerError', error.message);
  }
});

export default router;

import express from 'express';
const router = express.Router({ mergeParams: true });
import { addTask, getTasks, updateTaskStatus } from './service.js';
import { sendError } from '../../lib/errors.js';

router.post('/', (req, res) => {
  const task = addTask(req.params.id, req.body);
  if (!task) return sendError(res, 404, 'NotFoundError', 'Project not found');
  try {
    res.status(201).send({ task });
  } catch (error) {
    sendError(res, 500, 'InternalServerError', error.message);
  }
});

router.get('/', (req, res) => {
  const tasks = getTasks(req.params.id, req.query.status);
  if (!tasks) return sendError(res, 404, 'NotFoundError', 'Project not found');
  try {
    res.send({ tasks });
  } catch (error) {
    sendError(res, 500, 'InternalServerError', error.message);
  }
});

router.patch('/:taskId', (req, res) => {
  const task = updateTaskStatus(req.params.taskId, req.body.status);
  if (!task) return sendError(res, 404, 'NotFoundError', 'Task not found');
  try {
    res.send({ task });
  } catch (error) {
    sendError(res, 500, 'InternalServerError', error.message);
  }
});

export default router;

import express from 'express';
